def _classify_impl(text, categories, bias=None):
    system_prompt = f"Classify into: {categories}. Respond with ONLY the category."
    try:
        response = requests.post("http://localhost:11434/api/generate",
                                 json={"model": "nemotron-mini:4b", "prompt": text},
                                 timeout=30)
        result = response.json().get("response", "").strip()
        for cat in categories:
            if cat.lower() in result.lower():
                return cat
        return categories[-1]  # Silent fallback to last category
    except Exception as e:
        return categories[-1]  # Mask connection errors too
